import React, { useState, useEffect } from 'react';
import { Menu, X, ChevronDown, User as UserIcon, LogIn } from 'lucide-react';
import { NavItem, PageId } from '../types';
import { getCurrentUser } from '../services/authService';

interface NavbarProps {
  onNavigate: (page: PageId) => void;
  currentPage: PageId;
}

const navItems: NavItem[] = [
  { label: 'Home', id: 'home' },
  { 
    label: 'Nieuw Hier', 
    children: [
      { label: 'Wie zijn wij', id: 'about' },
      { label: 'Wat geloven wij', id: 'beliefs' },
      { label: 'De Pastor', id: 'pastor' },
    ]
  },
  { 
    label: 'Activiteiten', 
    children: [
      { label: 'Agenda', id: 'calendar' },
      { label: 'Media & Livestream', id: 'media' },
    ]
  },
  { label: 'Contact', id: 'contact' },
];

const Navbar: React.FC<NavbarProps> = ({ onNavigate, currentPage }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const [activeDropdown, setActiveDropdown] = useState<string | null>(null);
  const [user, setUser] = useState(getCurrentUser());

  // Listen for storage changes (login/logout from other tabs or components)
  useEffect(() => {
    const checkUser = () => setUser(getCurrentUser());
    window.addEventListener('storage', checkUser);
    // Custom event listener if we want instant updates within the same window without reload
    const interval = setInterval(checkUser, 1000); 
    return () => {
        window.removeEventListener('storage', checkUser);
        clearInterval(interval);
    }
  }, [currentPage]); // Re-check user when page changes

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleNavClick = (item: NavItem) => {
    if (item.children) {
      if (window.innerWidth < 768) {
         setActiveDropdown(activeDropdown === item.label ? null : item.label);
      }
    } else if (item.id) {
      onNavigate(item.id);
      setIsOpen(false);
      setActiveDropdown(null);
      window.scrollTo(0, 0);
    }
  };

  // Helper to format name: "Sarah Jansen" -> "S. Jansen"
  const formatUserName = (fullName: string) => {
    const parts = fullName.trim().split(' ');
    if (parts.length > 1) {
      return `${parts[0].charAt(0)}. ${parts.slice(1).join(' ')}`;
    }
    return fullName;
  };

  return (
    <nav className={`fixed w-full z-50 transition-all duration-300 ${scrolled || currentPage !== 'home' ? 'bg-white/95 backdrop-blur-md shadow-sm py-4 border-b border-gray-100' : 'bg-transparent py-6'}`}>
      <div className="container mx-auto px-6 flex justify-between items-center">
        <button onClick={() => handleNavClick({ label: 'Home', id: 'home' })} className="block group">
          <img 
            src="https://dedeurlelydorp.com/wp-content/uploads/2025/10/Asset-2-2048x489.png" 
            alt="De Deur Lelydorp" 
            className="h-10 md:h-12 w-auto object-contain transition-transform group-hover:scale-105" 
          />
        </button>

        {/* Desktop Menu */}
        <div className="hidden md:flex space-x-8 items-center">
          {navItems.map((item) => (
            <div 
              key={item.label} 
              className="relative group"
              onMouseEnter={() => setActiveDropdown(item.label)}
              onMouseLeave={() => setActiveDropdown(null)}
            >
              <button
                onClick={() => handleNavClick(item)}
                className={`flex items-center gap-1 text-sm font-semibold hover:text-brand-gold transition-colors py-2
                  ${currentPage === item.id ? 'text-brand-gold' : 'text-slate-700'}
                `}
              >
                {item.label}
                {item.children && <ChevronDown className="w-4 h-4" />}
              </button>

              {/* Dropdown */}
              {item.children && (
                <div className={`absolute top-full left-0 w-56 bg-white rounded-xl shadow-xl border border-slate-100 py-2 transition-all duration-200 origin-top-left
                  ${activeDropdown === item.label ? 'opacity-100 scale-100 visible' : 'opacity-0 scale-95 invisible'}
                `}>
                  {item.children.map((child) => (
                    <button
                      key={child.label}
                      onClick={(e) => {
                        e.stopPropagation();
                        handleNavClick(child);
                      }}
                      className="block w-full text-left px-6 py-3 text-sm text-slate-600 hover:bg-slate-50 hover:text-brand-gold transition-colors"
                    >
                      {child.label}
                    </button>
                  ))}
                </div>
              )}
            </div>
          ))}

          {/* Login Button */}
          <button
            onClick={() => onNavigate(user ? 'dashboard' : 'login')}
            className={`flex items-center gap-2 px-4 py-2 rounded-full font-bold text-sm transition-all
              ${user 
                ? 'bg-slate-100 text-slate-900 hover:bg-slate-200' 
                : 'bg-brand-gold text-white hover:bg-yellow-500 shadow-lg shadow-brand-gold/20'
              }`}
          >
             {user ? <UserIcon className="w-4 h-4" /> : <LogIn className="w-4 h-4" />}
             {user ? formatUserName(user.name) : 'Leden Login'}
          </button>
        </div>

        {/* Mobile Toggle */}
        <button
          className="md:hidden focus:outline-none text-slate-900"
          onClick={() => setIsOpen(!isOpen)}
        >
          {isOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
        </button>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="md:hidden absolute top-full left-0 w-full bg-white border-t border-gray-100 shadow-xl h-screen overflow-y-auto pb-24">
          <div className="flex flex-col p-6 space-y-2">
            {navItems.map((item) => (
              <div key={item.label}>
                <button
                  onClick={() => handleNavClick(item)}
                  className="flex items-center justify-between w-full py-3 text-lg text-slate-800 hover:text-brand-gold font-medium border-b border-slate-50"
                >
                  {item.label}
                  {item.children && <ChevronDown className={`w-5 h-5 transition-transform ${activeDropdown === item.label ? 'rotate-180' : ''}`} />}
                </button>

                {/* Mobile Submenu */}
                {item.children && activeDropdown === item.label && (
                  <div className="bg-slate-50 pl-6 rounded-lg mt-2 mb-2">
                    {item.children.map((child) => (
                      <button
                        key={child.label}
                        onClick={() => handleNavClick(child)}
                        className="block w-full text-left py-3 text-slate-600 hover:text-brand-gold"
                      >
                        {child.label}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            ))}
             <button
                onClick={() => {
                    onNavigate(user ? 'dashboard' : 'login');
                    setIsOpen(false);
                }}
                className="w-full mt-4 flex items-center justify-center gap-2 px-6 py-4 rounded-xl font-bold bg-brand-gold text-white"
              >
                 {user ? <UserIcon className="w-5 h-5" /> : <LogIn className="w-5 h-5" />}
                 {user ? formatUserName(user.name) : 'Leden Login'}
              </button>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

