        <div className="flex flex-col md:flex-row justify-between items-center mb-8 bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <div>
            <h1 className="text-3xl font-serif font-bold text-slate-900">Welkom, {user.name}</h1>
            <p className="text-slate-500">U bent ingelogd als <span className="font-semibold text-brand-red capitalize">{user.role}</span></p>
          </div>
          <button 
            onClick={handleLogoutAction}
            className="mt-4 md:mt-0 px-4 py-2 border border-red-200 text-red-600 bg-red-50 rounded-lg hover:bg-red-100 transition-colors flex items-center gap-2 font-medium"
          >
            <LogOut className="w-4 h-4" />
            Uitloggen
          </button>
        </div>

        <div className="grid lg:grid-cols-4 gap-8">

          {/* Sidebar Navigation (Mock) */}
          <div className="lg:col-span-1 space-y-4">
             <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                <div className="p-4 bg-slate-900 text-white font-bold flex items-center gap-2">
                   <LayoutDashboard className="w-5 h-5" /> Menu
                </div>
                <nav className="p-2">
                  <button className="w-full text-left px-4 py-3 rounded-lg bg-brand-red/10 text-brand-red font-medium flex items-center gap-3">
                    <Calendar className="w-5 h-5" />
                    Rooster & Agenda
                  </button>
                  <button className="w-full text-left px-4 py-3 rounded-lg text-slate-600 hover:bg-slate-50 transition-colors flex items-center gap-3">
                    <Settings className="w-5 h-5" />
                    Account Instellingen
                  </button>
                </nav>
             </div>

             {user.role === 'admin' && (
               <div className="bg-blue-50 border border-blue-200 p-4 rounded-xl text-sm text-blue-800">
                 <div className="flex items-center gap-2 font-bold mb-2">
                   <AlertCircle className="w-4 h-4" /> Admin Tip
                 </div>
                 Hiernaast kunt u de Google Agenda insluitcode plakken. Ga naar Google Calendar {'>'} Instellingen {'>'} Agenda integreren {'>'} Insluitcode.
               </div>
             )}
          </div>

          {/* Main Content Area */}
          <div className="lg:col-span-3">

            {/* Admin Editor */}
            {user.role === 'admin' && (
              <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 mb-8">
                <div className="flex justify-between items-center mb-4">
                  <h2 className="text-xl font-bold text-slate-900 flex items-center gap-2">
                    <Settings className="w-5 h-5 text-brand-red" />
                    Agenda Beheer
                  </h2>
                  <button 
                    onClick={() => setIsEditing(!isEditing)}
                    className="text-sm text-brand-red font-medium hover:underline"
                  >
                    {isEditing ? 'Annuleren' : 'Bewerk HTML Code'}
                  </button>
                </div>

                {isEditing && (
                  <motion.div 
                    initial={{ opacity: 0, height: 0 }} 
                    animate={{ opacity: 1, height: 'auto' }}
                    className="mb-4"
                  >
                    <textarea
                      value={embedHtml}
                      onChange={(e) => setEmbedHtml(e.target.value)}
                      className="w-full h-48 p-4 bg-slate-900 text-green-400 font-mono text-sm rounded-xl focus:outline-none focus:ring-2 focus:ring-brand-red"
                      placeholder="Plak hier uw <iframe> code..."
                    />
                    <div className="flex justify-end mt-4">
                      <button 
                        onClick={handleSave}
                        className="flex items-center gap-2 px-6 py-2 bg-brand-red text-white font-bold rounded-lg hover:bg-red-700 transition-colors"
                      >
                        <Save className="w-4 h-4" />
                        Opslaan & Publiceren
                      </button>
                    </div>
                  </motion.div>
                )}

                {successMsg && (
                  <div className="mb-4 p-3 bg-green-50 text-green-700 rounded-lg text-sm font-medium">
                    {successMsg}
                  </div>
                )}
              </div>
            )}

            {/* Calendar Display (Visible to User & Admin) */}
            <div className="bg-white rounded-2xl shadow-lg border border-slate-200 overflow-hidden">
               <div className="p-6 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
                  <h2 className="text-xl font-bold text-slate-900">Gemeente Agenda</h2>
                  <span className="text-xs font-mono bg-white border px-2 py-1 rounded text-slate-400">LIVE</span>
               </div>

               <div className="aspect-[4/3] md:aspect-video w-full bg-white relative">
                  {/* Dangerously Set Inner HTML for the Embed */}
                  <div 
                    className="w-full h-full [&>iframe]:w-full [&>iframe]:h-full"
                    dangerouslySetInnerHTML={{ __html: embedHtml }} 
                  />

                  {(!embedHtml || embedHtml.length < 10) && (
                    <div className="absolute inset-0 flex items-center justify-center text-slate-400">
                      Geen agenda geladen. Neem contact op met de beheerder.
                    </div>
                  )}
               </div>
            </div>

          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
